// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo;

import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class LeoConfidenceModelTest {

	@Test
	void firstSampleHasLowConfidence() {
		LeoConfidenceModel model = LeoConfidenceModel.empty()
				.observe(100.0d, 400.0d, 120.0d, 500.0d, 1L);

		assertTrue(model.confidence() <= 0.35d);
		assertTrue(model.rowQErrorMax() >= 4.0d);
	}

	@Test
	void stableSamplesClimbGradually() {
		LeoConfidenceModel three = stableSamples(3);
		LeoConfidenceModel eight = stableSamples(8);

		assertTrue(three.confidence() > 0.35d);
		assertTrue(three.confidence() <= 0.65d);
		assertTrue(eight.confidence() > three.confidence());
		assertTrue(eight.confidence() <= 0.90d);
	}

	@Test
	void highVarianceCapsConfidence() {
		LeoConfidenceModel stable = stableSamples(5);
		LeoConfidenceModel noisy = LeoConfidenceModel.empty()
				.observe(100.0d, 100.0d, 100.0d, 100.0d, 1L)
				.observe(100.0d, 10_000.0d, 100.0d, 10_000.0d, 2L)
				.observe(100.0d, 100.0d, 100.0d, 100.0d, 3L);

		assertTrue(noisy.confidence() < stable.confidence());
		assertTrue(noisy.rowQErrorMax() >= 100.0d);
	}

	@Test
	void recentSamplesHaveMoreWeightThanStaleSamples() {
		LeoConfidenceModel model = LeoConfidenceModel.empty()
				.observe(100.0d, 100.0d, 100.0d, 100.0d, 1L)
				.observe(100.0d, 100.0d, 100.0d, 100.0d, 2L)
				.observe(100.0d, 1_000.0d, 100.0d, 1_000.0d, 100L);

		assertTrue(model.rowCorrectionRatio() > 3.0d);
		assertTrue(model.confidence() < 0.65d);
	}

	private static LeoConfidenceModel stableSamples(int count) {
		LeoConfidenceModel model = LeoConfidenceModel.empty();
		for (int i = 1; i <= count; i++) {
			model = model.observe(100.0d, 100.0d, 100.0d, 100.0d, i);
		}
		return model;
	}
}
